from typing import Any, Literal

from fastapi import APIRouter, HTTPException
from pydantic import BaseModel

from backend.self_improver.engine import approve, execute, list_proposals, pending, propose, reject

router = APIRouter(prefix="/self", tags=["Self Improver"])


class ProposalStep(BaseModel):
    action: Literal["create_file", "edit_file", "delete_file"]
    path: str
    content: str | None = None
    find: str | None = None
    replace: str | None = None


class ProposalRequest(BaseModel):
    title: str
    reason: str
    steps: list[ProposalStep]


@router.post("/propose")
def propose_route(data: ProposalRequest):
    return propose(data.title, data.reason, [step.model_dump(exclude_none=True) for step in data.steps])


@router.get("/proposals")
def proposals_route():
    return {"items": list_proposals()}


@router.get("/pending")
def pending_route():
    return {"items": pending()}


@router.post("/approve/{pid}")
def approve_route(pid: str):
    ok = approve(pid)
    if not ok:
        raise HTTPException(status_code=404, detail="Proposal not found")
    return {"ok": True, "id": pid, "status": "approved"}


@router.post("/reject/{pid}")
def reject_route(pid: str):
    ok = reject(pid)
    if not ok:
        raise HTTPException(status_code=404, detail="Proposal not found")
    return {"ok": True, "id": pid, "status": "rejected"}


@router.post("/execute/{pid}")
def execute_route(pid: str):
    result = execute(pid)
    if not result.get("ok") and result.get("error") == "proposal not found":
        raise HTTPException(status_code=404, detail="Proposal not found")
    if not result.get("ok") and result.get("error") == "not approved":
        raise HTTPException(status_code=409, detail="Proposal not approved")
    return result

